# Vouchers Entry - on_cancel
journal_entries = frappe.get_all(
    "Journal Entry",
    filters={
        "cheque_no": doc.name,
        "docstatus": 1
    },
    pluck="name"
)

if not journal_entries:
    frappe.msgprint(f"No Journal Entry found for cheque_no {doc.name}")

for je_name in journal_entries:
    je = frappe.get_doc("Journal Entry", je_name)
    je.cancel()
    frappe.msgprint(f"Cancelled Journal Entry: {je_name}")

# Vouchers Entry - on_trash
journal_entries = frappe.get_all(
    "Journal Entry",
    filters={
        "cheque_no": doc.name
    },
    pluck="name"
)

if not journal_entries:
    frappe.msgprint(f"No Journal Entry found for cheque_no {doc.name}")

for je_name in journal_entries:
    je = frappe.get_doc("Journal Entry", je_name)
    
    # إلغاء القيد إذا كان Submitted
    if je.docstatus == 1:
        je.cancel()
        frappe.msgprint(f"Cancelled Journal Entry: {je_name}")
    
    # حذف القيد بعد الإلغاء أو إذا كان Draft
    je.delete()
    frappe.msgprint(f"Deleted Journal Entry: {je_name}")

